#include <bits/stdc++.h>
using namespace std;

int minFountains(vector<int>& ranges, int n) {
    // For each position, store the rightmost point it can cover
    vector<int> maxRight(n, 0);

    // Calculate the maximum right coverage for each position
    for(int i = 0; i < n; i++) {
        int left = max(0, i - ranges[i]);
        int right = min(n - 1, i + ranges[i]);
        maxRight[left] = max(maxRight[left], right);
    }

    // Count minimum fountains needed
    int count = 1;
    int currRight = maxRight[0];  // rightmost point current fountain can cover
    int nextRight = currRight;    // rightmost point next fountain can cover

    // Start from beginning
    int pos = 0;

    while(currRight < n - 1) {
        // Look for fountains that can extend coverage
        while(pos <= currRight) {
            nextRight = max(nextRight, maxRight[pos]);
            pos++;
        }

        // If we couldn't extend coverage, it's impossible
        if(nextRight <= currRight) return -1;

        // Move to next fountain
        currRight = nextRight;
        count++;
    }

    return count;
}

int main() {
    int t;
    cin >> t;
    while(t--) {
        int n;
        cin >> n;
        vector<int> ranges(n);
        for(int i = 0; i < n; i++) {
            cin >> ranges[i];
        }

        cout << minFountains(ranges, n) << endl;
    }
    return 0;
}
